mapper.select:
SELECT  COUNT(*)
  FROM  TB_BNDT_MANAGE
 WHERE  SUBSTRING(BNDT_DE, 1, 6) = #{bndtDe}

mapper.insert:
INSERT  INTO TB_BNDT_MANAGE
      ( BNDT_ID
      , BNDT_DE
      , RM
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{bndtId}
        , #{bndtDe}
        , #{remark}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_BNDT_MANAGE
   SET  RM = #{remark}
      , LAST_UPDUSR_ID = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  BNDT_ID = #{bndtId}
   AND  BNDT_DE = #{bndtDe}

mapper.delete:
DELETE
  FROM  TB_BNDT_MANAGE
 WHERE  BNDT_ID = #{bndtId}
   AND  BNDT_DE = #{bndtDe}

